// Limite depuis le webhook si dispo, sinon defaut 10, toujours 1-50
let limit = 10;
let summaryRecipient = 'ouat.abou34@gmail.com';
try {
  const allItems = $input.all();
  for (const item of allItems) {
    const bodyLimit = item.json?.body?.limit;
    if (bodyLimit !== undefined && bodyLimit !== null) {
      const parsed = parseInt(String(bodyLimit), 10);
      if (!isNaN(parsed)) limit = Math.max(1, Math.min(50, parsed));
      break;
    }
  }
} catch(e) { /* trigger sans body */ }
return [{ json: { maxEmails: limit, summaryRecipient, openAiModel: 'gpt-4o-mini', lookbackHours: 8 } }];

const cfg = $('Configuration').first().json;
const items = $input.all();
const excludedSenders = ['no-reply','noreply','newsletter','notification','notifications','marketing','facebookmail','linkedin'];
const excludedSubjects = ['newsletter','désabonnement','desabonnement','promotion','notification automatique','absence du bureau','automatic reply'];
const cutoff = new Date(Date.now() - Number(cfg.lookbackHours || 8) * 3600 * 1000);
const prepared = [];
const skipped = [];
for (const item of items) {
  const m = item.json;
  if (m.error) { skipped.push({ reason: 'erreur_lecture' }); continue; }
  const headers = m.payload?.headers || [];
  const from = headers.find(h => h.name === 'From')?.value || '';
  const subject = headers.find(h => h.name === 'Subject')?.value || '(sans objet)';
  const date = headers.find(h => h.name === 'Date')?.value || '';
  const senderLow = from.toLowerCase();
  const subjLow = subject.toLowerCase();
  const receivedAt = date ? new Date(date) : new Date();
  if (excludedSenders.some(x => senderLow.includes(x))) { skipped.push({ subject, reason: 'expediteur_exclu' }); continue; }
  if (excludedSubjects.some(x => subjLow.includes(x))) { skipped.push({ subject, reason: 'objet_exclu' }); continue; }
  if (receivedAt < cutoff) { skipped.push({ subject, reason: 'trop_ancien' }); continue; }
  prepared.push({ id: m.id, subject, sender: from, snippet: (m.snippet || '').substring(0, 500) });
}
if (prepared.length === 0) {
  return [{ json: { emails: [], skipped, no_emails: true, runAt: new Date().toISOString() } }];
}
return [{ json: { emails: prepared, skipped, no_emails: false, runAt: new Date().toISOString() } }];

const source = $('Préparer emails').first().json;
let parsed;
try {
  const content = $json.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch(e) {
  parsed = { emails: [], global_summary: 'Erreur parsing réponse IA.' };
}
const analyses = parsed.emails || [];
const urgent = analyses.filter(x => x.urgence === 'haute');
const repondre = analyses.filter(x => x.action === 'repondre');
const echeances = analyses.filter(x => x.echeance_detectee);
function line(x) {
  const senderShort = (x.sender || '').split('<')[0].trim() || 'Inconnu';
  return `• ${senderShort} | ${x.subject || '(sans objet)'} | ${x.resume || ''}${x.raison_urgence ? ' — ' + x.raison_urgence : ''}`;
}
const summaryText = [
  `🤖 Synthèse emails Jarvis — ${new Date().toLocaleString('fr-FR')}`,
  `Analysés: ${analyses.length} | Ignorés: ${(source.skipped || []).length}`,
  '',
  '🚨 Urgents',
  urgent.length ? urgent.map(line).join('\n') : '• Aucun.',
  '',
  '📩 À répondre',
  repondre.length ? repondre.map(line).join('\n') : '• Aucun.',
  '',
  '📅 Échéances',
  echeances.length ? echeances.map(x => `• ${x.date_echeance || 'date?'} | ${x.subject || ''} | ${x.resume || ''}`).join('\n') : '• Aucune.',
  '',
  '📋 Synthèse',
  parsed.global_summary || '• Rien à signaler.'
].join('\n');
// Structurer pour Redis
const emailMap = {};
for (const e of (source.emails || [])) emailMap[e.id] = e;
const emails_structured = analyses.map(a => {
  const orig = emailMap[a.id] || {};
  const fromStr = orig.sender || '';
  const m = fromStr.match(/^(.*?)\s*<(.+?)>$/);
  return {
    id: a.id,
    from: fromStr,
    from_name: (m?.[1] || fromStr).trim(),
    from_email: m?.[2] || fromStr,
    subject: orig.subject || '(sans objet)',
    snippet: orig.snippet || '',
    urgence: a.urgence || 'faible',
    action: a.action || 'lire',
    resume: a.resume || '',
    echeance: a.echeance_detectee ? (a.date_echeance || null) : null,
    source: 'gmail'
  };
});
return [{ json: { summaryText, processedCount: analyses.length, skippedCount: (source.skipped || []).length, emails_structured } }];
